import java.io.*;import java.util.*;class Main{static final class Solution{int bound;Map<Integer,Integer> remap=new HashMap<>();long state=1;Solution(int n,int[] blacklist){Set<Integer> blocked=new HashSet<>();for(int x:blacklist)blocked.add(x);bound=n-blacklist.length;List<Integer> tail=new ArrayList<>();for(int value=bound;value<n;value++)if(!blocked.contains(value))tail.add(value);int idx=0;for(int value:blacklist)if(value<bound)remap.put(value,tail.get(idx++));}int pick(){state=(state*1664525L+1013904223L)&0xffffffffL;int value=(int)(state%bound);return remap.getOrDefault(value,value);}}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder all=new StringBuilder();for(int tc=0;tc<t;tc++){int ops=Integer.parseInt(d[idx++]);List<String> out=new ArrayList<>();Solution solution=null;for(int i=0;i<ops;i++){String op=d[idx++];if(op.equals("C")){int n=Integer.parseInt(d[idx++]),b=Integer.parseInt(d[idx++]);int[] blacklist=new int[b];for(int j=0;j<b;j++)blacklist[j]=Integer.parseInt(d[idx++]);solution=new Solution(n,blacklist);out.add("null");}else out.add(String.valueOf(solution.pick()));}if(tc>0)all.append("\n\n");all.append("[").append(String.join(",",out)).append("]");}System.out.print(all);}}
